mapper.insert:
INSERT INTO pki_app.${tableName} (
    cert_serial, issuer_id, subject_id, not_after, first_activated_at, created_at, updated_at
) VALUES (
    #{record.certSerial}, #{record.issuerId}, #{record.subjectId}, #{record.notAfter}, #{record.firstActivatedAt}, #{record.createdAt}, #{record.updatedAt}
)
ON CONFLICT (cert_serial, issuer_id) DO UPDATE
SET subject_id = EXCLUDED.subject_id,
    not_after = EXCLUDED.not_after,
    first_activated_at = COALESCE(pki_app.${tableName}.first_activated_at, EXCLUDED.first_activated_at),
    updated_at = EXCLUDED.updated_at

mapper.select:
SELECT cert_serial, issuer_id, subject_id, not_after, first_activated_at, created_at, updated_at
FROM pki_app.${tableName}
WHERE subject_id = #{subjectId}
ORDER BY created_at DESC, updated_at DESC
LIMIT 1

SELECT cert_serial, issuer_id, subject_id, not_after, first_activated_at, created_at, updated_at
FROM pki_app.${tableName}
WHERE cert_serial = #{certSerial}
ORDER BY updated_at DESC

SELECT cert_serial, issuer_id, subject_id, not_after, first_activated_at, created_at, updated_at
FROM pki_app.${tableName}
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}
LIMIT 1

mapper.update:
UPDATE pki_app.${tableName}
SET updated_at = CURRENT_TIMESTAMP
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}
